// Hierarchical Bayesian model for binomial data (Gelman rat-tumor style)
// y_i ~ Binomial(n_i, theta_i)
// theta_i ~ Beta(alpha, beta)
// Prior: p(alpha, beta) proportional to (alpha + beta)^(-5/2)
data {
  int<lower=0> N;                 // number of groups/observations
  array[N] int<lower=0> n;        // trials per group
  array[N] int<lower=0> y;        // successes per group
}
parameters {
  real<lower=0> alpha;            // Beta shape parameter alpha
  real<lower=0> beta;             // Beta shape parameter beta
  vector<lower=0, upper=1>[N] theta;  // group-level success probabilities
}
model {
  // Prior on (alpha, beta): proportional to (alpha + beta)^(-5/2)
  target += -2.5 * log(alpha + beta);

  // Hierarchical prior on group probabilities
  theta ~ beta(alpha, beta);

  // Likelihood
  y ~ binomial(n, theta);
}

